+    if (not profiles_lists) {
+      diagnostic::warning("ignoring profiles for events where "
+                          "`metadata.profiles` is not a list")
+        .primary(self)
+        .emit(dh);
+      return make_string_list_function(nullptr);
+    }
+    if (dynamic_cast<arrow::NullArray*>(&*profiles_lists->values())) {
+      return make_string_list_function(nullptr);
